#!/usr/bin/env python3
# MBU Fault Injection Result Plots
# Generated by mbuSimulate.cc (AMD TensorBuffer method)
# Run on host: python3 plot_results.py

import os
import pandas as pd
import matplotlib.pyplot as plt
import matplotlib.ticker as mticker
import numpy as np

OUTDIR = os.path.dirname(os.path.abspath(__file__))

# Plot 1: Accuracy vs Number of Flipped Bits
acc_path = os.path.join(OUTDIR, 'accuracy_summary.csv')
if os.path.exists(acc_path):
    df = pd.read_csv(acc_path)
    baseline_acc = df['baseline_accuracy_pct'].iloc[0]
    x_labels = ['0 (baseline)'] + df['bits'].astype(str).tolist()
    y_vals   = [baseline_acc] + df['accuracy_pct'].tolist()
    colors   = ['forestgreen'] + ['steelblue']*len(df)
    fig, ax = plt.subplots(figsize=(10, 5))
    ax.bar(x_labels, y_vals, color=colors, edgecolor='black', width=0.5)
    ax.axhline(baseline_acc, color='forestgreen', linestyle='--', linewidth=1.2,
               label=f'Baseline {baseline_acc:.1f}%')
    ax.set_xlabel('Number of Flipped Bits (k)', fontsize=12)
    ax.set_ylabel('Accuracy (vs ground truth)', fontsize=12)
    ax.set_title('MBU Fault Injection: Accuracy vs Bit Count', fontsize=13)
    ax.set_ylim(0, 110)
    ax.yaxis.set_major_formatter(mticker.PercentFormatter())
    ax.legend(fontsize=10)
    for i, v in enumerate(y_vals):
        ax.text(i, v+1.5, f'{v:.1f}%', ha='center', fontsize=9)
    plt.tight_layout()
    plt.savefig(os.path.join(OUTDIR, 'plot_accuracy_vs_bits.png'), dpi=150)
    plt.close()
    print('[Plot] Saved: plot_accuracy_vs_bits.png')

bit_counts = [1,5,10,15,20]

# Plot 2: Probability Drop per Image
for k in bit_counts:
    csv_path = os.path.join(OUTDIR, f'results_k{k}_bits.csv')
    if not os.path.exists(csv_path): continue
    df = pd.read_csv(csv_path)
    df_v = df[(df['timeout']==0)&(df['crash']==0)].copy()
    if df_v.empty: continue
    avg = df_v.groupby('image_name')['prob_drop'].mean().reset_index()
    avg = avg.sort_values('image_name')
    names = [os.path.splitext(n)[0][-20:] for n in avg['image_name']]
    fig, ax = plt.subplots(figsize=(max(8,len(names)*0.8), 5))
    cols = ['tomato' if v>0.05 else 'steelblue' for v in avg['prob_drop']]
    ax.bar(names, avg['prob_drop'], color=cols, edgecolor='black')
    ax.axhline(0, color='black', linewidth=0.8, linestyle='--')
    ax.set_xlabel('Image', fontsize=11)
    ax.set_ylabel('Avg Prob Drop (baseline - faulty)', fontsize=10)
    ax.set_title(f'MBU k={k} bits: Prob Drop per Image', fontsize=12)
    plt.xticks(rotation=45, ha='right', fontsize=8)
    plt.tight_layout()
    plt.savefig(os.path.join(OUTDIR, f'plot_prob_drop_k{k}.png'), dpi=150)
    plt.close()
    print(f'[Plot] Saved: plot_prob_drop_k{k}.png')

# Plot 3: SDC Rate vs Bit Count
if os.path.exists(acc_path):
    df = pd.read_csv(acc_path)
    sdc_rate = 100 - df['accuracy_pct']
    fig, ax = plt.subplots(figsize=(8, 4))
    ax.plot(df['bits'], sdc_rate, 'o-', color='crimson', linewidth=2, markersize=7)
    ax.set_xlabel('Number of Flipped Bits (k)', fontsize=12)
    ax.set_ylabel('SDC Rate (%)', fontsize=12)
    ax.set_title('Silent Data Corruption Rate vs Bit Count', fontsize=13)
    ax.grid(True, alpha=0.4)
    ax.yaxis.set_major_formatter(mticker.PercentFormatter())
    plt.tight_layout()
    plt.savefig(os.path.join(OUTDIR, 'plot_sdc_rate.png'), dpi=150)
    plt.close()
    print('[Plot] Saved: plot_sdc_rate.png')

print('[Done] All plots saved to:', OUTDIR)
